module down_counter_with_load(
    input clk,
    input load,
    input [9:0] load_value,
    output reg [9:0] count);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load)
        count <= load_value;
    else
        count <= count - 1;
end
endmodule
